return $input.all().filter(item => {
    // 1. Оставляем только те лиды, у которых есть ссылка на сайт
    return item.json.website && item.json.website.trim() !== "";
}).map(item => {
    // 2. Очищаем телефон от скобок, дефисов и пробелов, оставляем только цифры и плюс
    let cleanPhone = item.json.phone.replace(/[^\d+]/g, '');

    // 3. Небольшая логика нормализации (если британский номер начинается с 0, меняем на +44)
    if (cleanPhone.startsWith('07')) {
        cleanPhone = '+44' + cleanPhone.substring(1);
    }

    // Возвращаем обновленный объект
    return {
        json: {
            name: item.json.name,
            address: item.json.address,
            phone: cleanPhone, // теперь телефон в идеальном формате
            website: item.json.website
        }
    };
});

